package com.onewindow.aichart.service;

import lombok.Data;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.time.Instant;
import java.util.concurrent.atomic.AtomicLong;

/**
 * NL2SQL 运行时状态统计服务
 * 
 * 职责：
 * 1. 统计 NL2SQL 查询次数（成功/失败）
 * 2. 统计 AI 调用次数和 Token 消耗
 * 3. 提供运行时长和健康状态
 * 
 * 使用方式：
 * - 内存存储，重启后清零
 * - 每分钟轮询获取状态
 */
@Service
public class RuntimeStatusService {

    /** 应用启动时间 */
    private final Instant startupTime = Instant.now();

    /** 查询计数器 */
    private final AtomicLong totalQueries = new AtomicLong(0);
    private final AtomicLong successQueries = new AtomicLong(0);
    private final AtomicLong failedQueries = new AtomicLong(0);

    /** AI 调用计数器 */
    private final AtomicLong aiCalls = new AtomicLong(0);
    private final AtomicLong aiTokens = new AtomicLong(0);
    private final AtomicLong aiErrors = new AtomicLong(0);

    /** Schema 加载状态 */
    private volatile int schemaTableCount = 0;
    private volatile boolean schemaInitialized = false;
    private volatile Instant lastSchemaRefreshTime = null;

    /**
     * 记录一次成功的 NL2SQL 查询
     */
    public void recordQuerySuccess() {
        totalQueries.incrementAndGet();
        successQueries.incrementAndGet();
    }

    /**
     * 记录一次失败的 NL2SQL 查询
     */
    public void recordQueryFailed() {
        totalQueries.incrementAndGet();
        failedQueries.incrementAndGet();
    }

    /**
     * 记录一次 AI 调用（成功）
     */
    public void recordAiCall(int tokens) {
        aiCalls.incrementAndGet();
        aiTokens.addAndGet(tokens);
    }

    /**
     * 记录一次 AI 调用（失败）
     */
    public void recordAiError() {
        aiCalls.incrementAndGet();
        aiErrors.incrementAndGet();
    }

    /**
     * 更新 Schema 状态
     */
    public void updateSchemaStatus(int tableCount) {
        this.schemaTableCount = tableCount;
        this.schemaInitialized = true;
        this.lastSchemaRefreshTime = Instant.now();
    }

    /**
     * 获取运行时状态
     */
    public RuntimeStatus getStatus() {
        return new RuntimeStatus(
                Duration.between(startupTime, Instant.now()),
                totalQueries.get(),
                successQueries.get(),
                failedQueries.get(),
                aiCalls.get(),
                aiTokens.get(),
                aiErrors.get(),
                schemaTableCount,
                schemaInitialized,
                lastSchemaRefreshTime
        );
    }

    /**
     * 获取成功率的百分比
     */
    public double getSuccessRate() {
        long total = totalQueries.get();
        if (total == 0) return 0.0;
        return (double) successQueries.get() / total * 100;
    }

    /**
     * 获取 AI 错误率
     */
    public double getAiErrorRate() {
        long total = aiCalls.get();
        if (total == 0) return 0.0;
        return (double) aiErrors.get() / total * 100;
    }

    @Data
    public static class RuntimeStatus {
        /** 运行时长 */
        private final String uptime;
        private final long uptimeSeconds;

        /** 查询统计 */
        private final long totalQueries;
        private final long successQueries;
        private final long failedQueries;
        private final double successRate;

        /** AI 统计 */
        private final long aiCalls;
        private final long aiTokens;
        private final long aiErrors;
        private final double aiErrorRate;

        /** Schema 状态 */
        private final int schemaTableCount;
        private final boolean schemaInitialized;
        private final String lastSchemaRefresh;

        public RuntimeStatus(Duration uptime,
                            long totalQueries,
                            long successQueries,
                            long failedQueries,
                            long aiCalls,
                            long aiTokens,
                            long aiErrors,
                            int schemaTableCount,
                            boolean schemaInitialized,
                            Instant lastSchemaRefreshTime) {
            this.uptimeSeconds = uptime.getSeconds();
            this.uptime = formatDuration(uptime);
            this.totalQueries = totalQueries;
            this.successQueries = successQueries;
            this.failedQueries = failedQueries;
            this.successRate = totalQueries > 0 ? (double) successQueries / totalQueries * 100 : 0.0;
            this.aiCalls = aiCalls;
            this.aiTokens = aiTokens;
            this.aiErrors = aiErrors;
            this.aiErrorRate = aiCalls > 0 ? (double) aiErrors / aiCalls * 100 : 0.0;
            this.schemaTableCount = schemaTableCount;
            this.schemaInitialized = schemaInitialized;
            this.lastSchemaRefresh = lastSchemaRefreshTime != null 
                    ? lastSchemaRefreshTime.toString() 
                    : null;
        }

        private static String formatDuration(Duration duration) {
            long days = duration.toDays();
            long hours = duration.toHoursPart();
            long minutes = duration.toMinutesPart();
            long seconds = duration.toSecondsPart();

            if (days > 0) {
                return String.format("%d天 %d小时 %d分 %d秒", days, hours, minutes, seconds);
            } else if (hours > 0) {
                return String.format("%d小时 %d分 %d秒", hours, minutes, seconds);
            } else if (minutes > 0) {
